 /// 解析十六进制输入字符串（支持 0x 前缀）
 fn parse_hex_input(s: &str) -> Option<usize> {
     let s = s.trim();
     let s = if s.starts_with("0x") || s.starts_with("0X") {
         &s[2..]
     } else {
         s
     };
     let clean: String = s.chars().filter(|c| c.is_ascii_hexdigit()).collect();
     if clean.is_empty() {
         return None;
     }
     usize::from_str_radix(&clean, 16).ok()
 }

