             InputMode::Help => {
                 draw_hex(f, app, data, area);
                 draw_help(f, app, area);
             }
             InputMode::SaveConfirm => {
                 draw_hex(f, app, data, area);
                 draw_save_dialog(f, app, area);
             }
             InputMode::ModeSelect => {
                 draw_hex(f, app, data, area);
                 draw_status(f, app, data, area);
                 draw_mode_dropdown(f, app, area);
             }
             _ => {
                 draw_hex(f, app, data, area);
                 draw_status(f, app, data, area);
             }
         }
     })?;
