 /// read-bin: 终端十六进制查看/编辑器
 ///
 /// 功能：文件分页浏览、三种显示模式（ASCII/HEX/UTF8）、
 /// hex/nibble/字符串搜索、字节编辑、撤销/重做、鼠标支持。
 ///
 /// 模块结构：
 /// - app: 应用状态管理
 /// - color_config: 颜色配置加载
 /// - search: 搜索引擎（三级位图索引）
 /// - utf8: UTF-8 解码与分类
 mod app;
 mod color_config;
 mod search;
 mod utf8;

