extern crate proc_macro;
use proc_macro::TokenStream;
use quote::quote;
use syn::parse_macroInput;

mod parser;
mod codegen;

use parser::TuiFile;

/// html!{ <Component : props /> } — 编译时展开为 ratatui 渲染代码
#[proc_macro]
pub fn html(input: TokenStream) -> TokenStream {
    let input_str = input.to_string();

    // 尝试解析为组件引用 <Component :app />
    if input_str.trim_start().starts_with('<') {
        let component = parse_macro_input!(input as parser::ComponentRef);
        let code = codegen::gen_component_call(&component);
        return code.into();
    }

    // 内联模板
    let template = parse_macro_input!(input as parser::InlineTemplate);
    let code = codegen::gen_inline_template(&template);
    code.into()
}

/// include_tui!("ui/statusbar.tui") — 编译时读取 .tui 文件并生成代码
#[proc_macro]
pub fn include_tui(input: TokenStream) -> TokenStream {
    let path = parse_macro_input!(input as syn::LitStr);
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR")
        .expect("CARGO_MANIFEST_DIR not set");
    let full_path = std::path::Path::new(&manifest_dir).join(path.value());

    let content = std::fs::read_to_string(&full_path)
        .unwrap_or_else(|e| panic!("Failed to read {}: {}", full_path.display(), e));

    let tui: TuiFile = syn::parse_str(&content)
        .unwrap_or_else(|e| panic!("Failed to parse {}: {}", full_path.display(), e));

    let code = codegen::gen_tui_file(&tui);
    code.into()
}

use syn::parse::{Parse, ParseStream};
use syn::{Token, LitStr, Ident};

// ─── .tui 文件结构 ─────────────────────────────────────────

/// 一个完整的 .tui 文件
pub struct TuiFile {
    pub template: TemplateBlock,
    pub style: Option<StyleBlock>,
    pub script: Option<ScriptBlock>,
}

impl Parse for TuiFile {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut template = None;
        let mut style = None;
        let mut script = None;

        while !input.is_empty() {
            let ident: Ident = input.parse()?;
            let ident_str = ident.to_string();
            match ident_str.as_str() => {
                "template" => {
                    let content;
                    syn::braced!(content in input);
                    template = Some(content.parse::<TemplateBlock>()?);
                }
                "style" => {
                    let content;
                    syn::braced!(content in input);
                    style = Some(content.parse::<StyleBlock>()?);
                }
                "script" => {
                    // 解析可选的 lang="rust" 属性
                    let attrs = input.call(parse_attrs)?;
                    let lang = attrs.iter().find_map(|a| {
                        if a.name == "lang" { Some(a.value.clone()) } else { None }
                    });
                    if let Some(lang) = &lang {
                        if lang != "rust" {
                            return Err(syn::Error::new(
                                input.span(),
                                format!("Unsupported script lang: '{}'. Only 'rust' is supported.", lang),
                            ));
                        }
                    }
                    let content;
                    syn::braced!(content in input);
                    let script_content: syn::Block = content.parse()?;
                    script = Some(ScriptBlock { lang, block: script_content });
                }
                _ => {
                    return Err(syn::Error::new(
                        ident.span(),
                        format!("Expected 'template', 'style', or 'script', got '{}'", ident_str),
                    ));
                }
            }
        }

        Ok(TuiFile {
            template: template.ok_or_else(|| syn::Error::new(input.span(), "Missing <template> block"))?,
            style,
            script,
        })
    }
}

// ─── 属性解析 ───────────────────────────────────────────────

struct Attr {
    name: String,
    value: String,
}

fn parse_attrs(input: ParseStream) -> syn::Result<Vec<Attr>> {
    let mut attrs = Vec::new();
    // 解析 [lang="rust"] 形式的属性
    if input.peek(syn::token::Bracket) {
        let content;
        syn::bracketed!(content in input);
        while !content.is_empty() {
            let name: Ident = content.parse()?;
            let _eq: Token![=] = content.parse()?;
            let value: LitStr = content.parse()?;
            attrs.push(Attr {
                name: name.to_string(),
                value: value.value(),
            });
            if content.peek(Token![,]) {
                let _: Token![,] = content.parse()?;
            }
        }
    }
    Ok(attrs)
}

// ─── Template ───────────────────────────────────────────────

pub struct TemplateBlock {
    pub nodes: Vec<TemplateNode>,
}

impl Parse for TemplateBlock {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut nodes = Vec::new();
        while !input.is_empty() {
            nodes.push(input.parse::<TemplateNode>()?);
        }
        Ok(TemplateBlock { nodes })
    }
}

pub enum TemplateNode {
    Element(Element),
    Text(String),
    Interpolation(String),
    ForLoop { var: String, iter: String, body: Vec<TemplateNode> },
    IfCond { expr: String, body: Vec<TemplateNode> },
}

pub struct Element {
    pub tag: String,
    pub classes: Vec<String>,
    pub props: Vec<Prop>,
    pub events: Vec<EventBinding>,
    pub children: Vec<TemplateNode>,
    pub self_closing: bool,
}

pub struct Prop {
    pub name: String,
    pub value: String,
    pub bind: bool, // :prop 语法
}

pub struct EventBinding {
    pub name: String,    // "click", "scroll", "keydown"
    pub handler: String, // "on_click"
}

impl Parse for TemplateNode {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        // 检查 {{ for ... }}
        if input.peek(Token![{]) && input.peek2(Token![{]) {
            return parse_brace_block(input);
        }

        // 文本节点
        if !input.peek(Token![<]) {
            return parse_text_node(input);
        }

        // 元素节点
        input.parse::<Token![<]>()?;
        let tag: Ident = input.parse()?;
        let tag_str = tag.to_string();

        // 解析属性
        let mut classes = Vec::new();
        let mut props = Vec::new();
        let mut events = Vec::new();

        while !input.peek(Token![>]) && !input.peek(Token![/]) {
            if input.peek(Token![@]) {
                // @click="handler"
                let _: Token![@] = input.parse()?;
                let event_name: Ident = input.parse()?;
                let _: Token![=] = input.parse()?;
                let handler: LitStr = input.parse()?;
                events.push(EventBinding {
                    name: event_name.to_string(),
                    handler: handler.value(),
                });
            } else if input.peek(Token![:]) {
                // :prop="expr"
                let _: Token![:] = input.parse()?;
                let prop_name: Ident = input.parse()?;
                let _: Token![=] = input.parse()?;
                let value: LitStr = input.parse()?;
                props.push(Prop {
                    name: prop_name.to_string(),
                    value: value.value(),
                    bind: true,
                });
            } else if input.peek2(Token![=]) || input.peek2(Token![>]) || input.peek2(Token![/]) {
                // class="xxx" or prop="xxx"
                let attr_name: Ident = input.parse()?;
                let attr_str = attr_name.to_string();
                if attr_str == "class" {
                    let _: Token![=] = input.parse()?;
                    let val: LitStr = input.parse()?;
                    classes.extend(val.value().split_whitespace().map(|s| s.to_string()));
                } else {
                    let _: Token![=] = input.parse()?;
                    let val: LitStr = input.parse()?;
                    props.push(Prop {
                        name: attr_str,
                        value: val.value(),
                        bind: false,
                    });
                }
            } else {
                break;
            }
        }

        // 自闭合 <Tag />
        if input.peek(Token![/]) {
            input.parse::<Token![/]>()?;
            input.parse::<Token![>]>()?;
            return Ok(TemplateNode::Element(Element {
                tag: tag_str,
                classes,
                props,
                events,
                children: Vec::new(),
                self_closing: true,
            }));
        }

        // > ... </Tag>
        input.parse::<Token![>]>()?;
        let mut children = Vec::new();
        while !input.peek(Token![<]) || !(input.peek2(Ident) || input.peek2(Token![/])) {
            if input.is_empty() {
                return Err(syn::Error::new(input.span(), format!("Unclosed <{}>", tag_str)));
            }
            children.push(input.parse::<TemplateNode>()?);
        }

        // </Tag>
        input.parse::<Token![<]>()?;
        input.parse::<Token![/]>()?;
        let close_tag: Ident = input.parse()?;
        if close_tag != tag_str {
            return Err(syn::Error::new(
                close_tag.span(),
                format!("Mismatched closing tag: expected </{}>, got </{}>", tag_str, close_tag),
            ));
        }
        input.parse::<Token![>]>()?;

        Ok(TemplateNode::Element(Element {
            tag: tag_str,
            classes,
            props,
            events,
            children,
            self_closing: false,
        }))
    }
}

fn parse_text_node(input: ParseStream) -> syn::Result<TemplateNode> {
    let mut text = String::new();
    while !input.is_empty() && !input.peek(Token![<]) && !input.peek(Token![{]) {
        let ident: Ident = input.parse()?;
        if !text.is_empty() { text.push(' '); }
        text.push_str(&ident.to_string());
    }
    Ok(TemplateNode::Text(text))
}

fn parse_brace_block(input: ParseStream) -> syn::Result<TemplateNode> {
    // {{ ... }}
    let _: Token![{] = input.parse()?;
    let _: Token![{] = input.parse()?;

    let mut inner = String::new();
    let mut depth = 0u8;
    loop {
        if input.peek(Token![}]) && input.peek2(Token![}]) {
            if depth == 0 {
                input.parse::<Token![}]>()?;
                input.parse::<Token![}]>()?;
                break;
            }
            depth -= 1;
        }
        if input.peek(Token![{]) {
            depth += 1;
        }
        // 吃掉所有 token 作为文本
        let token: proc_macro2::TokenTree = input.parse()?;
        inner.push_str(&token.to_string());
    }

    let inner = inner.trim();

    // {{ for x in iter }} ... {{ /for }}
    if inner.starts_with("for ") {
        let rest = &inner[4..];
        let parts: Vec<&str> = rest.splitn(2, " in ").collect();
        if parts.len() == 2 {
            let var = parts[0].trim().to_string();
            let iter = parts[1].trim().to_string();
            let mut body = Vec::new();
            while !input.is_empty() {
                if input.peek(Token![{]) && input.peek2(Token![{]) {
                    let peeked = input.fork();
                    let _: Token![{] = peeked.parse().unwrap();
                    let _: Token![{] = peeked.parse().unwrap();
                    let mut check_inner = String::new();
                    while !peeked.is_empty() && !peeked.peek(Token![}]) {
                        let t: proc_macro2::TokenTree = peeked.parse().unwrap();
                        check_inner.push_str(&t.to_string());
                    }
                    if check_inner.trim() == "/for" {
                        // 消费 {{ /for }}
                        let _: Token![{] = input.parse()?;
                        let _: Token![{] = input.parse()?;
                        let mut skip = String::new();
                        while !input.is_empty() && !input.peek(Token![}]) {
                            let t: proc_macro2::TokenTree = input.parse()?;
                            skip.push_str(&t.to_string());
                        }
                        let _: Token![}] = input.parse()?;
                        let _: Token![}] = input.parse()?;
                        break;
                    }
                }
                body.push(input.parse::<TemplateNode>()?);
            }
            return Ok(TemplateNode::ForLoop { var, iter, body });
        }
    }

    // {{ if expr }} ... {{ /if }}
    if inner.starts_with("if ") {
        let expr = inner[3..].trim().to_string();
        let mut body = Vec::new();
        while !input.is_empty() {
            if input.peek(Token![{]) && input.peek2(Token![{]) {
                let peeked = input.fork();
                let _: Token![{] = peeked.parse().unwrap();
                let _: Token![{] = peeked.parse().unwrap();
                let mut check_inner = String::new();
                while !peeked.is_empty() && !peeked.peek(Token![}]) {
                    let t: proc_macro2::TokenTree = peeked.parse().unwrap();
                    check_inner.push_str(&t.to_string());
                }
                if check_inner.trim() == "/if" {
                    let _: Token![{] = input.parse()?;
                    let _: Token![{] = input.parse()?;
                    let mut skip = String::new();
                    while !input.is_empty() && !input.peek(Token![}]) {
                        let t: proc_macro2::TokenTree = input.parse()?;
                        skip.push_str(&t.to_string());
                    }
                    let _: Token![}] = input.parse()?;
                    let _: Token![}] = input.parse()?;
                    break;
                }
            }
            body.push(input.parse::<TemplateNode>()?);
        }
        return Ok(TemplateNode::IfCond { expr, body });
    }

    // 普通插值 {{ expr }}
    Ok(TemplateNode::Interpolation(inner.to_string()))
}

// ─── Style ──────────────────────────────────────────────────

pub struct StyleBlock {
    pub rules: Vec<StyleRule>,
}

pub struct StyleRule {
    pub selector: String,   // ".class" or ".class:pseudo"
    pub properties: Vec<StyleProp>,
}

pub struct StyleProp {
    pub name: String,  // "fg", "bg", "bold", etc.
    pub value: String, // "auto", "red", "[20,20,40]", "true", etc.
}

impl Parse for StyleBlock {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut rules = Vec::new();
        while !input.is_empty() {
            // .class { ... }
            let dot: Token![.] = input.parse()?;
            let selector: Ident = input.parse()?;
            let mut sel_str = format!(".{}", selector);

            // 可选伪类 :pseudo
            if input.peek(Token![:]) {
                let _: Token![:] = input.parse()?;
                let pseudo: Ident = input.parse()?;
                sel_str.push_str(&format!(":{}", pseudo));
            }

            let content;
            syn::braced!(content in input);
            let mut properties = Vec::new();
            while !content.is_empty() {
                let prop_name: Ident = content.parse()?;
                let _: Token![:] = content.parse()?;
                // 读取值直到逗号或末尾
                let mut val = String::new();
                let mut depth = 0u8;
                while !content.is_empty() {
                    if depth == 0 && content.peek(Token![,]) {
                        let _: Token![,] = content.parse()?;
                        break;
                    }
                    if content.peek(syn::token::Bracket) {
                        depth += 1;
                        let bracket_content;
                        syn::bracketed!(bracket_content in content);
                        val.push('[');
                        while !bracket_content.is_empty() {
                            let t: proc_macro2::TokenTree = bracket_content.parse()?;
                            val.push_str(&t.to_string());
                        }
                        val.push(']');
                        depth -= 1;
                        continue;
                    }
                    if content.peek(Token![}]) {
                        break;
                    }
                    let t: proc_macro2::TokenTree = content.parse()?;
                    val.push_str(&t.to_string());
                }
                properties.push(StyleProp {
                    name: prop_name.to_string(),
                    value: val.trim().to_string(),
                });
            }
            rules.push(StyleRule { selector: sel_str, properties });
        }
        Ok(StyleBlock { rules })
    }
}

