// ─── html! 宏的输入解析 ────────────────────────────────────

/// <Component :app /> 或 <Component prop="val" />
pub struct ComponentRef {
    pub tag: String,
    pub props: Vec<Prop>,
    pub events: Vec<EventBinding>,
}

impl Parse for ComponentRef {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        input.parse::<Token![<]>()?;
        let tag: Ident = input.parse()?;
        let mut props = Vec::new();
        let mut events = Vec::new();

        while !input.peek(Token![>]) && !input.peek(Token![/]) {
            if input.peek(Token![@]) {
                let _: Token![@] = input.parse()?;
                let event_name: Ident = input.parse()?;
                let _: Token![=] = input.parse()?;
                let handler: LitStr = input.parse()?;
                events.push(EventBinding {
                    name: event_name.to_string(),
                    handler: handler.value(),
                });
            } else if input.peek(Token![:]) {
                let _: Token![:] = input.parse()?;
                let prop_name: Ident = input.parse()?;
                let _: Token![=] = input.parse()?;
                let value: LitStr = input.parse()?;
                props.push(Prop {
                    name: prop_name.to_string(),
                    value: value.value(),
                    bind: true,
                });
            } else {
                break;
            }
        }

        if input.peek(Token![/]) {
            input.parse::<Token![/]>()?;
        }
        input.parse::<Token![>]>()?;

        Ok(ComponentRef {
            tag: tag.to_string(),
            props,
            events,
        })
    }
}

/// 内联模板（直接在 html!{ } 中写模板）
pub struct InlineTemplate {
    pub nodes: Vec<TemplateNode>,
}

impl Parse for InlineTemplate {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut nodes = Vec::new();
        while !input.is_empty() {
            nodes.push(input.parse::<TemplateNode>()?);
        }
        Ok(InlineTemplate { nodes })
    }
}

use quote::quote;
use proc_macro2::TokenStream;

use crate::parser::*;

/// 生成 .tui 文件的完整代码
pub fn gen_tui_file(tui: &TuiFile) -> TokenStream {
    let mut tokens = TokenStream::new();

    // 生成样式查询函数
    if let Some(style) = &tui.style {
        tokens.extend(gen_style_block(style));
    }

    // 生成模板渲染函数
    tokens.extend(gen_template_block(&tui.template));

    // 生成脚本函数（直接透传）
    if let Some(script) = &tui.script {
        tokens.extend(script.block.clone());
    }

    tokens
}

/// 生成样式查询：fn style_resolve(class: &str, pseudo: Option<&str>) -> Style
fn gen_style_block(style: &StyleBlock) -> TokenStream {
    let mut match_arms = Vec::new();

    for rule in &style.rules {
        let selector = &rule.selector;
        let props = &rule.properties;

        // 解析选择器
        let (class, pseudo) = if let Some(colon_pos) = selector.find(':') {
            let class = &selector[1..colon_pos]; // 去掉 .
            let pseudo = &selector[colon_pos+1..];
            (class, Some(pseudo))
        } else {
            (&selector[1..], None) // 去掉 .
        };

        let style_expr = gen_style_expr(props);

        match pseudo {
            Some(p) => {
                match_arms.push(quote! {
                    (#class, Some(#p)) => #style_expr,
                });
            }
            None => {
                match_arms.push(quote! {
                    (#class, _) => #style_expr,
                });
            }
        }
    }

    quote! {
        fn style_resolve(class: &str, pseudo: Option<&str>) -> ratatui::style::Style {
            match (class, pseudo) {
                #(#match_arms)*
                _ => ratatui::style::Style::default(),
            }
        }
    }
}

/// 从样式属性列表生成 Style 表达式
fn gen_style_expr(props: &[StyleProp]) -> TokenStream {
    let mut fg = None;
    let mut bg = None;
    let mut bold = None;
    let mut dim = None;

    for prop in props {
        match prop.name.as_str() {
            "fg" => fg = Some(parse_color_value(&prop.value)),
            "bg" => bg = Some(parse_color_value(&prop.value)),
            "bold" => bold = Some(prop.value == "true"),
            "dim" => dim = Some(prop.value == "true"),
            _ => {}
        }
    }

    let mut style = quote! { ratatui::style::Style::default() };

    if let Some(fg_expr) = fg {
        style = quote! { #style.fg(#fg_expr) };
    }
    if let Some(bg_expr) = bg {
        style = quote! { #style.bg(#bg_expr) };
    }
    if let Some(true) = bold {
        style = quote! { #style.add_modifier(ratatui::style::Modifier::BOLD) };
    }
    if let Some(true) = dim {
        style = quote! { #style.add_modifier(ratatui::style::Modifier::DIM) };
    }

    style
}

/// 解析颜色值
fn parse_color_value(val: &str) -> TokenStream {
    match val {
        "auto" => quote! { crate::color_config::AUTO_FG_SENTINEL },
        "black" => quote! { ratatui::style::Color::Black },
        "red" => quote! { ratatui::style::Color::Red },
        "green" => quote! { ratatui::style::Color::Green },
        "yellow" => quote! { ratatui::style::Color::Yellow },
        "blue" => quote! { ratatui::style::Color::Blue },
        "magenta" => quote! { ratatui::style::Color::Magenta },
        "cyan" => quote! { ratatui::style::Color::Cyan },
        "white" => quote! { ratatui::style::Color::White },
        "darkgray" | "dark_gray" => quote! { ratatui::style::Color::DarkGray },
        _ => {
            // 尝试解析 [r, g, b]
            if val.starts_with('[') && val.ends_with(']') {
                let inner = &val[1..val.len()-1];
                let parts: Vec<u8> = inner.split(',')
                    .filter_map(|s| s.trim().parse().ok())
                    .collect();
                if parts.len() == 3 {
                    let r = parts[0];
                    let g = parts[1];
                    let b = parts[2];
                    return quote! { ratatui::style::Color::Rgb(#r, #g, #b) };
                }
            }
            // fallback
            quote! { ratatui::style::Color::White }
        }
    }
}

/// 生成模板渲染函数
fn gen_template_block(template: &TemplateBlock) -> TokenStream {
    let body = gen_nodes(&template.nodes);
    quote! {
        pub fn render(f: &mut ratatui::Frame, app: &crate::app::App, data: &[u8], area: ratatui::layout::Rect) {
            #body
        }
    }
}

/// 生成节点列表的渲染代码
fn gen_nodes(nodes: &[TemplateNode]) -> TokenStream {
    let mut stmts = Vec::new();
    for node in nodes {
        stmts.push(gen_node(node));
    }
    quote! { #(#stmts)* }
}

/// 生成单个节点的渲染代码
fn gen_node(node: &TemplateNode) -> TokenStream {
    match node {
        TemplateNode::Element(elem) => gen_element(elem),
        TemplateNode::Text(text) => {
            let text_str = text.as_str();
            quote! {
                // text node: #text_str
            }
        }
        TemplateNode::Interpolation(expr) => {
            let expr_tokens: proc_macro2::TokenStream = expr.parse()
                .unwrap_or_else(|_| quote! { "????" });
            quote! {
                // interpolation: #expr_tokens
            }
        }
        TemplateNode::ForLoop { var, iter, body } => {
            let var_ident: proc_macro2::TokenStream = var.parse().unwrap();
            let iter_expr: proc_macro2::TokenStream = iter.parse().unwrap();
            let body_code = gen_nodes(body);
            quote! {
                for #var_ident in #iter_expr {
                    #body_code
                }
            }
        }
        TemplateNode::IfCond { expr, body } => {
            let cond: proc_macro2::TokenStream = expr.parse().unwrap();
            let body_code = gen_nodes(body);
            quote! {
                if #cond {
                    #body_code
                }
            }
        }
    }
}

/// 生成元素的渲染代码
fn gen_element(elem: &Element) -> TokenStream {
    let tag = &elem.tag;

    match tag.as_str() {
        "Text" => gen_text_element(elem),
        "Statusbar" => gen_statusbar(elem),
        "Popup" => gen_popup(elem),
        "Row" => gen_row(elem),
        "Byte" => gen_byte(elem),
        "Scrollable" => gen_scrollable(elem),
        "Scrollbar" => gen_scrollbar(elem),
        _ => {
            // 未知标签：尝试作为组件调用
            let tag_ident: proc_macro2::TokenStream = tag.parse().unwrap();
            let children = gen_nodes(&elem.children);
            quote! {
                // component: #tag_ident
                #children
            }
        }
    }
}

/// <Text class="x">content</Text>
fn gen_text_element(elem: &Element) -> TokenStream {
    let class = elem.classes.first().map(|c| c.as_str()).unwrap_or("");
    let content = gen_interpolation_content(&elem.children);
    let pseudo = get_pseudo_from_events(elem);

    quote! {
        {
            let sty = style_resolve(#class, #pseudo);
            let text = #content;
            spans.push(ratatui::text::Span::styled(text, sty));
        }
    }
}

/// <Statusbar>...</Statusbar>
fn gen_statusbar(elem: &Element) -> TokenStream {
    let children = gen_nodes(&elem.children);
    let click_handler = get_event_handler(elem, "click");

    quote! {
        {
            // 清除底栏区域
            f.render_widget(ratatui::widgets::Clear, ratatui::layout::Rect::new(0, area.height - 1, area.width, 1));
            let mut spans: Vec<ratatui::text::Span> = Vec::new();
            #children
            f.render_widget(
                ratatui::widgets::Paragraph::new(ratatui::text::Line::from(spans)),
                ratatui::layout::Rect::new(0, area.height - 1, area.width, 1),
            );
            #click_handler
        }
    }
}

/// <Popup class="x" title="...">...</Popup>
fn gen_popup(elem: &Element) -> TokenStream {
    let title = get_prop_value(elem, "title").unwrap_or_default();
    let title_tokens: proc_macro2::TokenStream = title.parse().unwrap_or_else(|_| quote! { "" });
    let children = gen_nodes(&elem.children);

    quote! {
        {
            let h = (area.height * 8 / 10).max(10).min(40);
            let w = (area.width * 9 / 10).max(30).min(80);
            let y = (area.height.saturating_sub(h)) / 2;
            let x = (area.width.saturating_sub(w)) / 2;
            let popup = ratatui::layout::Rect::new(x, y, w, h);
            f.render_widget(ratatui::widgets::Clear, popup);
            f.render_widget(
                ratatui::widgets::Block::default()
                    .borders(ratatui::widgets::Borders::ALL)
                    .border_style(ratatui::style::Style::default().fg(ratatui::style::Color::Gray).bg(ratatui::style::Color::Rgb(20, 20, 40)))
                    .title(#title_tokens)
                    .style(ratatui::style::Style::default().bg(ratatui::style::Color::Rgb(20, 20, 40))),
                popup,
            );
            #children
        }
    }
}

/// <Row>...</Row>
fn gen_row(elem: &Element) -> TokenStream {
    let children = gen_nodes(&elem.children);
    quote! {
        {
            #children
            lines.push(ratatui::text::Line::from(spans));
            spans = Vec::new();
        }
    }
}

/// <Byte :offset="..." />
fn gen_byte(elem: &Element) -> TokenStream {
    let offset_expr = get_prop_value(elem, "offset")
        .map(|v| v.parse::<proc_macro2::TokenStream>().unwrap_or_else(|_| quote! { 0 }))
        .unwrap_or_else(|| quote! { 0 });

    quote! {
        {
            let byte_offset = #offset_expr;
            if byte_offset < data.len() {
                let b = data[byte_offset];
                let sty = crate::byte_style(b, app.mode);
                let disp = crate::byte_disp(b, app.mode);
                spans.push(ratatui::text::Span::styled(disp, sty));
            }
        }
    }
}

/// <Scrollable>...</Scrollable>
fn gen_scrollable(_elem: &Element) -> TokenStream {
    // Scrollable 的逻辑由父组件处理，这里只渲染子内容
    quote! { {} }
}

/// <Scrollbar />
fn gen_scrollbar(_elem: &Element) -> TokenStream {
    quote! { {} }
}

// ─── 辅助函数 ───────────────────────────────────────────────

/// 生成插值内容的字符串表达式
fn gen_interpolation_content(nodes: &[TemplateNode]) -> TokenStream {
    if nodes.is_empty() {
        return quote! { String::new() };
    }

    let mut parts = Vec::new();
    for node in nodes {
        match node {
            TemplateNode::Text(t) => {
                let s = t.as_str();
                parts.push(quote! { #s });
            }
            TemplateNode::Interpolation(expr) => {
                let expr_tokens: proc_macro2::TokenStream = expr.parse().unwrap();
                parts.push(quote! { &#expr_tokens });
            }
            _ => {}
        }
    }

    if parts.len() == 1 {
        parts[0].clone()
    } else {
        quote! { format!(#(#parts),*) }
    }
}

/// 从事件绑定中获取伪类
fn get_pseudo_from_events(_elem: &Element) -> Option<&'static str> {
    // 伪类来自 style 选择器，不在这里处理
    None
}

/// 获取元素的事件处理器
fn get_event_handler(_elem: &Element, _event_name: &str) -> TokenStream {
    // 事件处理在 dispatch_event 中统一处理
    quote! {}
}

/// 获取元素的属性值
fn get_prop_value(elem: &Element, name: &str) -> Option<String> {
    elem.props.iter()
        .find(|p| p.name == name)
        .map(|p| p.value.clone())
}

