/// 生成组件调用代码
pub fn gen_component_call(component: &ComponentRef) -> TokenStream {
    let tag = &component.tag;
    let tag_ident: proc_macro2::TokenStream = tag.parse().unwrap();

    quote! {
        {
            crate::components::#tag_ident::render(f, app, data, area);
        }
    }
}

/// 生成内联模板代码
pub fn gen_inline_template(template: &InlineTemplate) -> TokenStream {
    gen_nodes(&template.nodes)
}

use proc_macro2::{TokenTree, TokenStream};
use syn::parse::{Parse, ParseStream};
use syn::{Token, LitStr, Ident};

// ─── .tui 文件结构 ─────────────────────────────────────────

pub struct TuiFile {
    pub template: TemplateBlock,
    pub style: Option<StyleBlock>,
    pub script: Option<ScriptBlock>,
}

impl Parse for TuiFile {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut template = None;
        let mut style = None;
        let mut script = None;

        while !input.is_empty() {
            let ident: Ident = input.parse()?;
            let ident_str = ident.to_string();

            match ident_str.as_str() => {
                "template" => {
                    let content;
                    syn::braced!(content in input);
                    template = Some(content.parse::<TemplateBlock>()?);
                }
                "style" => {
                    let content;
                    syn::braced!(content in input);
                    style = Some(content.parse::<StyleBlock>()?);
                }
                "script" => {
                    let lang = parse_script_attrs(input)?;
                    let content;
                    syn::braced!(content in input);
                    let block: syn::Block = content.parse()?;
                    script = Some(ScriptBlock { lang, block });
                }
                _ => {
                    return Err(syn::Error::new(
                        ident.span(),
                        format!("Expected 'template', 'style', or 'script', got '{}'", ident_str),
                    ));
                }
            }
        }

        Ok(TuiFile {
            template: template.ok_or_else(|| syn::Error::new(input.span(), "Missing <template> block"))?,
            style,
            script,
        })
    }
}

fn parse_script_attrs(input: ParseStream) -> syn::Result<Option<String>> {
    if input.peek(syn::token::Bracket) {
        let content;
        syn::bracketed!(content in input);
        let name: Ident = content.parse()?;
        if name == "lang" {
            let _: Token![=] = content.parse()?;
            let val: LitStr = content.parse()?;
            return Ok(Some(val.value()));
        }
    }
    Ok(None)
}

// ─── Template ───────────────────────────────────────────────

pub struct TemplateBlock {
    pub nodes: Vec<TemplateNode>,
}

impl Parse for TemplateBlock {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut nodes = Vec::new();
        while !input.is_empty() {
            nodes.push(input.parse::<TemplateNode>()?);
        }
        Ok(TemplateBlock { nodes })
    }
}

pub enum TemplateNode {
    Element(Element),
    Text(String),
    Interpolation(String),
    ForLoop { var: String, iter: String, body: Vec<TemplateNode> },
    IfCond { expr: String, body: Vec<TemplateNode> },
}

pub struct Element {
    pub tag: String,
    pub classes: Vec<String>,
    pub props: Vec<Prop>,
    pub events: Vec<EventBinding>,
    pub children: Vec<TemplateNode>,
    pub self_closing: bool,
}

pub struct Prop {
    pub name: String,
    pub value: String,
    pub bind: bool,
}

pub struct EventBinding {
    pub name: String,
    pub handler: String,
}

impl Parse for TemplateNode {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        // {{ ... }} 块
        if input.peek(Token![{]) {
            return parse_brace_block(input);
        }

        // < 元素
        if input.peek(Token![<]) {
            input.parse::<Token![<]>()?;
            let tag: Ident = input.parse()?;
            let tag_str = tag.to_string();

            let mut classes = Vec::new();
            let mut props = Vec::new();
            let mut events = Vec::new();

            // 解析属性
            while !input.peek(Token![>]) && !input.peek(Token![/]) {
                if input.peek(Token![@]) {
                    let _: Token![@] = input.parse()?;
                    let event_name: Ident = input.parse()?;
                    let _: Token![=] = input.parse()?;
                    let handler: LitStr = input.parse()?;
                    events.push(EventBinding {
                        name: event_name.to_string(),
                        handler: handler.value(),
                    });
                } else if input.peek(Token![:]) {
                    let _: Token![:] = input.parse()?;
                    let prop_name: Ident = input.parse()?;
                    let _: Token![=] = input.parse()?;
                    let value: LitStr = input.parse()?;
                    props.push(Prop {
                        name: prop_name.to_string(),
                        value: value.value(),
                        bind: true,
                    });
                } else {
                    let attr_name: Ident = input.parse()?;
                    let attr_str = attr_name.to_string();
                    if attr_str == "class" {
                        let _: Token![=] = input.parse()?;
                        let val: LitStr = input.parse()?;
                        classes.extend(val.value().split_whitespace().map(|s| s.to_string()));
                    } else {
                        let _: Token![=] = input.parse()?;
                        let val: LitStr = input.parse()?;
                        props.push(Prop {
                            name: attr_str,
                            value: val.value(),
                            bind: false,
                        });
                    }
                }
            }

            // 自闭合
            if input.peek(Token![/]) {
                input.parse::<Token![/]>()?;
                input.parse::<Token![>]>()?;
                return Ok(TemplateNode::Element(Element {
                    tag: tag_str, classes, props, events,
                    children: Vec::new(), self_closing: true,
                }));
            }

            input.parse::<Token![>]>()?;

            // 子节点
            let mut children = Vec::new();
            loop {
                if input.is_empty() {
                    return Err(syn::Error::new(input.span(), format!("Unclosed <{}>", tag_str)));
                }
                // 遇到 </ 或 <Ident 就是闭合标签
                if input.peek(Token![<]) && input.peek2(Token![/]) {
                    break;
                }
                children.push(input.parse::<TemplateNode>()?);
            }

            // </Tag>
            input.parse::<Token![<]>()?;
            input.parse::<Token![/]>()?;
            let close_tag: Ident = input.parse()?;
            if close_tag != tag_str {
                return Err(syn::Error::new(
                    close_tag.span(),
                    format!("Mismatched: expected </{}>, got </{}>", tag_str, close_tag),
                ));
            }
            input.parse::<Token![>]>()?;

            return Ok(TemplateNode::Element(Element {
                tag: tag_str, classes, props, events,
                children, self_closing: false,
            }));
        }

        // 文本 token
        let token: TokenTree = input.parse()?;
        Ok(TemplateNode::Text(token.to_string()))
    }
}

fn parse_brace_block(input: ParseStream) -> syn::Result<TemplateNode> {
    // 吃掉 {{
    input.parse::<Token![{]>()?;
    input.parse::<Token![{]>()?;

    // 收集内容直到 }}
    let mut inner_tokens = Vec::new();
    let mut depth = 0u32;
    loop {
        if input.is_empty() {
            return Err(syn::Error::new(input.span(), "Unclosed {{"));
        }
        if input.peek(Token![}]) {
            // 看看是不是 }}
            let fork = input.fork();
            fork.parse::<Token![}]>()?;
            if fork.peek(Token![}]) {
                if depth == 0 {
                    // 消费 }}
                    input.parse::<Token![}]>()?;
                    input.parse::<Token![}]>()?;
                    break;
                }
                depth -= 1;
            }
        }
        if input.peek(Token![{]) {
            depth += 1;
        }
        let token: TokenTree = input.parse()?;
        inner_tokens.push(token);
    }

    let inner: String = inner_tokens.iter().map(|t| t.to_string()).collect();
    let inner = inner.trim();

    // {{ for x in iter }}
    if inner.starts_with("for ") {
        let rest = &inner[4..];
        if let Some(pos) = rest.find(" in ") {
            let var = rest[..pos].trim().to_string();
            let iter = rest[pos+4..].trim().to_string();
            let mut body = Vec::new();
            while !input.is_empty() {
                if input.peek(Token![{]) {
                    // 检查是否是 {{ /for }}
                    let fork = input.fork();
                    fork.parse::<Token![{]>()?;
                    fork.parse::<Token![{]>()?;
                    let mut check_tokens = Vec::new();
                    while !fork.is_empty() && !fork.peek(Token![}]) {
                        if let Ok(t) = fork.parse::<TokenTree>() {
                            check_tokens.push(t);
                        }
                    }
                    let check: String = check_tokens.iter().map(|t| t.to_string()).collect();
                    if check.trim() == "/for" {
                        // 消费 {{ /for }}
                        input.parse::<Token![{]>()?;
                        input.parse::<Token![{]>()?;
                        while !input.is_empty() && !input.peek(Token![}]) {
                            input.parse::<TokenTree>()?;
                        }
                        input.parse::<Token![}]>()?;
                        input.parse::<Token![}]>()?;
                        break;
                    }
                }
                body.push(input.parse::<TemplateNode>()?);
            }
            return Ok(TemplateNode::ForLoop { var, iter, body });
        }
    }

    // {{ if expr }}
    if inner.starts_with("if ") {
        let expr = inner[3..].trim().to_string();
        let mut body = Vec::new();
        while !input.is_empty() {
            if input.peek(Token![{]) {
                let fork = input.fork();
                fork.parse::<Token![{]>()?;
                fork.parse::<Token![{]>()?;
                let mut check_tokens = Vec::new();
                while !fork.is_empty() && !fork.peek(Token![}]) {
                    if let Ok(t) = fork.parse::<TokenTree>() {
                        check_tokens.push(t);
                    }
                }
                let check: String = check_tokens.iter().map(|t| t.to_string()).collect();
                if check.trim() == "/if" {
                    input.parse::<Token![{]>()?;
                    input.parse::<Token![{]>()?;
                    while !input.is_empty() && !input.peek(Token![}]) {
                        input.parse::<TokenTree>()?;
                    }
                    input.parse::<Token![}]>()?;
                    input.parse::<Token![}]>()?;
                    break;
                }
            }
            body.push(input.parse::<TemplateNode>()?);
        }
        return Ok(TemplateNode::IfCond { expr, body });
    }

    // 普通插值 {{ expr }}
    Ok(TemplateNode::Interpolation(inner.to_string()))
}

// ─── Style ──────────────────────────────────────────────────

pub struct StyleBlock {
    pub rules: Vec<StyleRule>,
}

pub struct StyleRule {
    pub selector: String,
    pub properties: Vec<StyleProp>,
}

pub struct StyleProp {
    pub name: String,
    pub value: String,
}

impl Parse for StyleBlock {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut rules = Vec::new();
        while !input.is_empty() {
            let _: Token![.] = input.parse()?;
            let selector: Ident = input.parse()?;
            let mut sel_str = format!(".{}", selector);

            if input.peek(Token![:]) {
                let _: Token![:] = input.parse()?;
                let pseudo: Ident = input.parse()?;
                sel_str.push_str(&format!(":{}", pseudo));
            }

            let content;
            syn::braced!(content in input);
            let mut properties = Vec::new();
            while !content.is_empty() {
                let prop_name: Ident = content.parse()?;
                let _: Token![:] = content.parse()?;
                let mut val = String::new();
                while !content.is_empty() && !content.peek(Token![,]) && !content.peek(Token![}]) {
                    let t: TokenTree = content.parse()?;
                    val.push_str(&t.to_string());
                }
                properties.push(StyleProp {
                    name: prop_name.to_string(),
                    value: val.trim().to_string(),
                });
                if content.peek(Token![,]) {
                    let _: Token![,] = content.parse()?;
                }
            }
            rules.push(StyleRule { selector: sel_str, properties });
        }
        Ok(StyleBlock { rules })
    }
}

