/// 检查 cursor 处的 token 是否是指定字符串
fn cursor_token_eq(cursor: &syn::parse::ParseBuffer, s: &str) -> bool {
    if cursor.is_empty() {
        return false;
    }
    // 使用 cursor 的 peek 方法，但需要检查 token 文本
    // 由于 ParseStream 不能 peek 关闭括号，我们检查 fork
    let fork = cursor.fork();
    if let Ok(tt) = fork.parse::<TokenTree>() {
        tt.to_string() == s
    } else {
        false
    }
}

fn parse_brace_block(input: ParseStream) -> syn::Result<TemplateNode> {
    // 将所有 token 收集到 Vec，避免 ParseStream 的 delimiter 匹配问题
    let mut all_tokens = Vec::new();
    while !input.is_empty() {
        let tt: TokenTree = input.parse()?;
        all_tokens.push(tt);
    }

    // 在 token 列表中查找 {{
    let mut pos = 0;
    while pos < all_tokens.len() {
        if all_tokens[pos].to_string() == "{" {
            if pos + 1 < all_tokens.len() && all_tokens[pos + 1].to_string() == "{" {
                // 找到 {{，收集内容直到 }}
                pos += 2;
                let mut inner_tokens = Vec::new();
                let mut depth = 0u32;
                while pos < all_tokens.len() {
                    let s = all_tokens[pos].to_string();
                    if s == "{" {
                        depth += 1;
                        inner_tokens.push(all_tokens[pos].clone());
                        pos += 1;
                    } else if s == "}" {
                        if depth > 0 {
                            depth -= 1;
                            inner_tokens.push(all_tokens[pos].clone());
                            pos += 1;
                        } else if pos + 1 < all_tokens.len() && all_tokens[pos + 1].to_string() == "}" {
                            // 找到 }}
                            pos += 2;
                            break;
                        } else {
                            inner_tokens.push(all_tokens[pos].clone());
                            pos += 1;
                        }
                    } else {
                        inner_tokens.push(all_tokens[pos].clone());
                        pos += 1;
                    }
                }

                let inner: String = inner_tokens.iter().map(|t| t.to_string()).collect();
                let inner = inner.trim();

                // 解析 {{ for / if / interpolation }}
                if inner.starts_with("for ") {
                    let rest = &inner[4..];
                    if let Some(p) = rest.find(" in ") {
                        let var = rest[..p].trim().to_string();
                        let iter = rest[p + 4..].trim().to_string();
                        // 从 pos 开始找 {{ /for }}，递归解析中间的节点
                        let mut body = Vec::new();
                        let mut body_tokens = Vec::new();
                        while pos < all_tokens.len() {
                            let s = all_tokens[pos].to_string();
                            if s == "{" && pos + 1 < all_tokens.len() && all_tokens[pos + 1].to_string() == "{" {
                                if pos + 2 < all_tokens.len() {
                                    let check: String = all_tokens[pos..pos + 3].iter()
                                        .map(|t| t.to_string()).collect();
                                    // 简单检查: {{后面跟 /for
                                    let rest_check: String = all_tokens[pos..].iter()
                                        .take(6).map(|t| t.to_string()).collect();
                                    if rest_check.contains("/for") {
                                        // 跳过 {{ /for }}
                                        while pos < all_tokens.len() {
                                            let s2 = all_tokens[pos].to_string();
                                            pos += 1;
                                            if s2 == "}" && pos < all_tokens.len() && all_tokens[pos].to_string() == "}" {
                                                pos += 1;
                                                break;
                                            }
                                        }
                                        break;
                                    }
                                }
                            }
                            body_tokens.push(all_tokens[pos].clone());
                            pos += 1;
                        }
                        // 递归解析 body_tokens
                        let body_input = syn::parse_str::<InlineNodes>(
                            &body_tokens.iter().map(|t| t.to_string()).collect::<String>()
                        ).unwrap_or(InlineNodes { nodes: Vec::new() });
                        return Ok(TemplateNode::ForLoop { var, iter, body: body_input.nodes });
                    }
                }

                if inner.starts_with("if ") {
                    let expr = inner[3..].trim().to_string();
                    let mut body_tokens = Vec::new();
                    while pos < all_tokens.len() {
                        let s = all_tokens[pos].to_string();
                        if s == "{" && pos + 1 < all_tokens.len() && all_tokens[pos + 1].to_string() == "{" {
                            let rest_check: String = all_tokens[pos..].iter()
                                .take(6).map(|t| t.to_string()).collect();
                            if rest_check.contains("/if") {
                                while pos < all_tokens.len() {
                                    let s2 = all_tokens[pos].to_string();
                                    pos += 1;
                                    if s2 == "}" && pos < all_tokens.len() && all_tokens[pos].to_string() == "}" {
                                        pos += 1;
                                        break;
                                    }
                                }
                                break;
                            }
                        }
                        body_tokens.push(all_tokens[pos].clone());
                        pos += 1;
                    }
                    let body_input = syn::parse_str::<InlineNodes>(
                        &body_tokens.iter().map(|t| t.to_string()).collect::<String>()
                    ).unwrap_or(InlineNodes { nodes: Vec::new() });
                    return Ok(TemplateNode::IfCond { expr, body: body_input.nodes });
                }

                // 普通插值
                return Ok(TemplateNode::Interpolation(inner.to_string()));
            }
        }
        pos += 1;
    }

    Err(syn::Error::new(input.span(), "Expected {{ }} block"))
}

/// 辅助结构：从 token 字符串解析节点列表
struct InlineNodes {
    nodes: Vec<TemplateNode>,
}

impl syn::parse::Parse for InlineNodes {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        let mut nodes = Vec::new();
        while !input.is_empty() {
            nodes.push(input.parse::<TemplateNode>()?);
        }
        Ok(InlineNodes { nodes })
    }
}

