impl Parse for StyleBlock {
    fn parse(input: ParseStream) -> syn::Result<Self> {
        // 收集所有 token 避免 ParseStream delimiter 问题
        let mut all_tokens = Vec::new();
        while !input.is_empty() {
            let tt: TokenTree = input.parse()?;
            all_tokens.push(tt);
        }

        let mut rules = Vec::new();
        let mut pos = 0;
        while pos < all_tokens.len() {
            // 跳过非 . 开头的 token
            if all_tokens[pos].to_string() != "." {
                pos += 1;
                continue;
            }
            pos += 1; // 跳过 .

            // 读取选择器名
            let selector_name = all_tokens[pos].to_string();
            pos += 1;
            let mut sel_str = format!(".{}", selector_name);

            // 可选伪类
            if pos < all_tokens.len() && all_tokens[pos].to_string() == ":" {
                pos += 1;
                let pseudo = all_tokens[pos].to_string();
                pos += 1;
                sel_str.push_str(&format!(":{}", pseudo));
            }

            // 跳过 {
            if pos < all_tokens.len() && all_tokens[pos].to_string() == "{" {
                pos += 1;
            }

            // 收集属性直到 }
            let mut properties = Vec::new();
            let mut prop_name = String::new();
            let mut expect_colon = false;
            let mut expect_value = false;
            let mut val_tokens = Vec::new();
            let mut brace_depth = 0u32;

            while pos < all_tokens.len() {
                let s = all_tokens[pos].to_string();
                if s == "{" {
                    brace_depth += 1;
                    val_tokens.push(all_tokens[pos].clone());
                    pos += 1;
                } else if s == "}" {
                    if brace_depth > 0 {
                        brace_depth -= 1;
                        val_tokens.push(all_tokens[pos].clone());
                        pos += 1;
                    } else {
                        // 结束当前规则
                        // 保存最后一个属性
                        if !prop_name.is_empty() && !val_tokens.is_empty() {
                            let val: String = val_tokens.iter().map(|t| t.to_string()).collect();
                            properties.push(StyleProp {
                                name: prop_name.clone(),
                                value: val.trim().to_string(),
                            });
                            val_tokens.clear();
                        }
                        pos += 1;
                        break;
                    }
                } else if s == ":" && brace_depth == 0 && !expect_value {
                    expect_colon = false;
                    expect_value = true;
                    pos += 1;
                } else if s == "," && brace_depth == 0 {
                    // 保存当前属性
                    if !prop_name.is_empty() && !val_tokens.is_empty() {
                        let val: String = val_tokens.iter().map(|t| t.to_string()).collect();
                        properties.push(StyleProp {
                            name: prop_name.clone(),
                            value: val.trim().to_string(),
                        });
                        val_tokens.clear();
                        prop_name.clear();
                        expect_value = false;
                    }
                    pos += 1;
                } else if !expect_value && brace_depth == 0 {
                    // 属性名
                    prop_name = s;
                    expect_colon = true;
                    pos += 1;
                } else {
                    // 属性值
                    val_tokens.push(all_tokens[pos].clone());
                    pos += 1;
                }
            }

            rules.push(StyleRule { selector: sel_str, properties });
        }
        Ok(StyleBlock { rules })
    }
}

