use proc_macro2::{TokenTree, TokenStream, Span};
use std::iter::Peekable;

// ─── .tui 文件结构 ─────────────────────────────────────────

pub struct TuiFile {
    pub template: TemplateBlock,
    pub style: Option<StyleBlock>,
    pub script: Option<ScriptBlock>,
}

pub struct TemplateBlock {
    pub nodes: Vec<TemplateNode>,
}

pub enum TemplateNode {
    Element(Element),
    Text(String),
    Interpolation(String),
    ForLoop { var: String, iter: String, body: Vec<TemplateNode> },
    IfCond { expr: String, body: Vec<TemplateNode> },
}

pub struct Element {
    pub tag: String,
    pub classes: Vec<String>,
    pub props: Vec<Prop>,
    pub events: Vec<EventBinding>,
    pub children: Vec<TemplateNode>,
    pub self_closing: bool,
}

pub struct Prop {
    pub name: String,
    pub value: String,
}

pub struct EventBinding {
    pub name: String,
    pub handler: String,
}

pub struct StyleBlock {
    pub rules: Vec<StyleRule>,
}

pub struct StyleRule {
    pub selector: String,
    pub properties: Vec<StyleProp>,
}

pub struct StyleProp {
    pub name: String,
    pub value: String,
}

pub struct ScriptBlock {
    pub lang: Option<String>,
    pub block: TokenStream,
}

pub struct ComponentRef {
    pub tag: String,
    pub props: Vec<Prop>,
    pub events: Vec<EventBinding>,
}

pub struct InlineTemplate {
    pub nodes: Vec<TemplateNode>,
}

// ─── Token 工具 ────────────────────────────────────────────

struct TokenStreamParser {
    tokens: Vec<TokenTree>,
    pos: usize,
}

impl TokenStreamParser {
    fn new(stream: TokenStream) -> Self {
        Self { tokens: stream.into_iter().collect(), pos: 0 }
    }

    fn is_empty(&self) -> bool { self.pos >= self.tokens.len() }

    fn peek(&self) -> Option<&TokenTree> { self.tokens.get(self.pos) }

    fn peek_str(&self) -> Option<String> {
        self.peek().map(|t| t.to_string())
    }

    fn next(&mut self) -> Option<TokenTree> {
        if self.pos < self.tokens.len() {
            let t = self.tokens[self.pos].clone();
            self.pos += 1;
            Some(t)
        } else {
            None
        }
    }

    fn expect(&mut self, s: &str) -> Result<(), String> {
        match self.next() {
            Some(t) if t.to_string() == s => Ok(()),
            Some(t) => Err(format!("Expected '{}', got '{}'", s, t)),
            None => Err(format!("Expected '{}', got EOF", s)),
        }
    }

    fn expect_ident(&mut self) -> Result<String, String> {
        match self.next() {
            Some(TokenTree::Ident(i)) => Ok(i.to_string()),
            Some(t) => Err(format!("Expected identifier, got '{}'", t)),
            None => Err("Expected identifier, got EOF".into()),
        }
    }

    fn expect_literal(&mut self) -> Result<String, String> {
        match self.next() {
            Some(TokenTree::Literal(l)) => {
                let s = l.to_string();
                // 去掉引号
                Ok(s.trim_matches('"').to_string())
            }
            Some(t) => Err(format!("Expected string literal, got '{}'", t)),
            None => Err("Expected string literal, got EOF".into()),
        }
    }

    fn skip_group(&mut self) {
        if let Some(TokenTree::Group(_)) = self.peek() {
            self.next();
        }
    }

    fn collect_until(&mut self, stop: &str) -> Vec<TokenTree> {
        let mut tokens = Vec::new();
        while !self.is_empty() {
            if self.peek_str().as_deref() == Some(stop) {
                break;
            }
            tokens.push(self.next().unwrap());
        }
        tokens
    }

    fn rest_string(&self) -> String {
        self.tokens[self.pos..].iter().map(|t| t.to_string()).collect::<Vec<_>>().join(" ")
    }
}

// ─── 解析 .tui 文件 ────────────────────────────────────────

pub fn parse_tui_file(input: TokenStream) -> Result<TuiFile, String> {
    let mut p = TokenStreamParser::new(input);
    let mut template = None;
    let mut style = None;
    let mut script = None;

    while !p.is_empty() {
        let section = p.expect_ident()?;
        match section.as_str() {
            "template" => {
                let block = p.expect_brace_group()?;
                let mut tp = TokenStreamParser::new(block);
                template = Some(parse_template_block(&mut tp)?);
            }
            "style" => {
                let block = p.expect_brace_group()?;
                let mut sp = TokenStreamParser::new(block);
                style = Some(parse_style_block(&mut sp)?);
            }
            "script" => {
                let lang = if p.peek_str().as_deref() == Some("[") {
                    p.next(); // [
                    let name = p.expect_ident()?;
                    p.expect("=")?;
                    let val = p.expect_literal()?;
                    p.expect("]")?;
                    Some(val)
                } else {
                    None
                };
                let block = p.expect_brace_group()?;
                script = Some(ScriptBlock { lang, block: block });
            }
            _ => return Err(format!("Expected 'template', 'style', or 'script', got '{}'", section)),
        }
    }

    Ok(TuiFile {
        template: template.ok_or("Missing <template> block")?,
        style,
        script,
    })
}

impl TokenStreamParser {
    fn expect_brace_group(&mut self) -> Result<TokenStream, String> {
        match self.next() {
            Some(TokenTree::Group(g)) if g.delimiter() == proc_macro2::Delimiter::Brace => {
                Ok(g.stream())
            }
            Some(t) => Err(format!("Expected {{...}}, got '{}'", t)),
            None => Err("Expected {{...}}, got EOF".into()),
        }
    }
}

// ─── 解析 template ─────────────────────────────────────────

fn parse_template_block(p: &mut TokenStreamParser) -> Result<TemplateBlock, String> {
    let mut nodes = Vec::new();
    while !p.is_empty() {
        nodes.push(parse_template_node(p)?);
    }
    Ok(TemplateBlock { nodes })
}

fn parse_template_node(p: &mut TokenStreamParser) -> Result<TemplateNode, String> {
    let first = p.peek_str().ok_or("Unexpected EOF")?;

    // {{ ... }} 块
    if first == "{" {
        return parse_brace_block(p);
    }

    // < 元素
    if first == "<" {
        return parse_element(p);
    }

    // 文本 token
    let token = p.next().unwrap();
    Ok(TemplateNode::Text(token.to_string()))
}

fn parse_element(p: &mut TokenStreamParser) -> Result<TemplateNode, String> {
    p.expect("<")?;
    let tag = p.expect_ident()?;

    let mut classes = Vec::new();
    let mut props = Vec::new();
    let mut events = Vec::new();

    // 解析属性直到 > 或 /
    loop {
        let next = p.peek_str().ok_or("Unexpected EOF in element")?;
        if next == ">" || next == "/" { break; }

        if next == "@" {
            p.next(); // @
            let event_name = p.expect_ident()?;
            p.expect("=")?;
            let handler = p.expect_literal()?;
            events.push(EventBinding { name: event_name, handler });
        } else if next == ":" {
            p.next(); // :
            let prop_name = p.expect_ident()?;
            p.expect("=")?;
            let value = p.expect_literal()?;
            props.push(Prop { name: prop_name, value });
        } else {
            let attr_name = p.expect_ident()?;
            p.expect("=")?;
            let value = p.expect_literal()?;
            if attr_name == "class" {
                classes.extend(value.split_whitespace().map(|s| s.to_string()));
            } else {
                props.push(Prop { name: attr_name, value });
            }
        }
    }

    // 自闭合 <Tag />
    if p.peek_str().as_deref() == Some("/") {
        p.next(); // /
        p.expect(">")?;
        return Ok(TemplateNode::Element(Element {
            tag, classes, props, events,
            children: Vec::new(), self_closing: true,
        }));
    }

    p.expect(">")?;

    // 子节点直到 </Tag>
    let mut children = Vec::new();
    loop {
        let next = p.peek_str().ok_or(format!("Unclosed <{}>", tag))?;
        if next == "<" {
            // 检查是不是 </Tag>
            let fork_pos = p.pos;
            p.next(); // <
            let next2 = p.peek_str();
            p.pos = fork_pos; // 回退
            if next2.as_deref() == Some("/") {
                break;
            }
        }
        children.push(parse_template_node(p)?);
    }

    // </Tag>
    p.expect("<")?;
    p.expect("/")?;
    let close_tag = p.expect_ident()?;
    if close_tag != tag {
        return Err(format!("Mismatched: expected </{}>, got </{}>", tag, close_tag));
    }
    p.expect(">")?;

    Ok(TemplateNode::Element(Element {
        tag, classes, props, events,
        children, self_closing: false,
    }))
}

fn parse_brace_block(p: &mut TokenStreamParser) -> Result<TemplateNode, String> {
    p.expect("{")?;
    p.expect("{")?;

    // 收集内容直到 }}
    let mut inner_tokens = Vec::new();
    let mut depth = 0u32;
    loop {
        let s = p.peek_str().ok_or("Unclosed {{")?;
        if s == "{" {
            depth += 1;
            inner_tokens.push(p.next().unwrap());
        } else if s == "}" {
            if depth > 0 {
                depth -= 1;
                inner_tokens.push(p.next().unwrap());
            } else {
                // 可能是 }}
                p.next(); // }
                p.expect("}")?;
                break;
            }
        } else {
            inner_tokens.push(p.next().unwrap());
        }
    }

    let inner: String = inner_tokens.iter().map(|t| t.to_string()).collect();
    let inner = inner.trim().to_string();

    // {{ for x in iter }}
    if inner.starts_with("for ") {
        let rest = &inner[4..];
        if let Some(pos) = rest.find(" in ") {
            let var = rest[..pos].trim().to_string();
            let iter = rest[pos + 4..].trim().to_string();

            // 解析 body 直到 {{ /for }}
            let mut body_tokens = Vec::new();
            while !p.is_empty() {
                let s = p.peek_str().unwrap_or_default();
                if s == "{" {
                    // 看看是不是 {{ /for }}
                    let save = p.pos;
                    p.next(); // {
                    let s2 = p.peek_str().unwrap_or_default();
                    if s2 == "{" {
                        // 收集几个 token 看看
                        let mut check = vec!["{{".to_string()];
                        let save2 = p.pos;
                        p.next(); // {
                        for _ in 0..5 {
                            if let Some(s3) = p.peek_str() {
                                check.push(s3);
                                p.next();
                            }
                        }
                        p.pos = save2; // 回退到第二个 {
                        p.pos = save;  // 回退到第一个 {

                        let check_str = check.join(" ");
                        if check_str.contains("/for") {
                            // 跳过 {{ /for }}
                            p.next(); // {
                            p.next(); // {
                            while !p.is_empty() && p.peek_str().as_deref() != Some("}") {
                                p.next();
                            }
                            p.next(); // }
                            p.next(); // }
                            break;
                        }
                    } else {
                        p.pos = save;
                    }
                }
                body_tokens.push(p.next().unwrap());
            }

            let body = parse_body_tokens(&body_tokens)?;
            return Ok(TemplateNode::ForLoop { var, iter, body });
        }
    }

    // {{ if expr }}
    if inner.starts_with("if ") {
        let expr = inner[3..].trim().to_string();
        let mut body_tokens = Vec::new();
        while !p.is_empty() {
            let s = p.peek_str().unwrap_or_default();
            if s == "{" {
                let save = p.pos;
                p.next();
                let s2 = p.peek_str().unwrap_or_default();
                if s2 == "{" {
                    let mut check = vec!["{{".to_string()];
                    let save2 = p.pos;
                    p.next();
                    for _ in 0..5 {
                        if let Some(s3) = p.peek_str() {
                            check.push(s3);
                            p.next();
                        }
                    }
                    p.pos = save2;
                    p.pos = save;
                    let check_str = check.join(" ");
                    if check_str.contains("/if") {
                        p.next();
                        p.next();
                        while !p.is_empty() && p.peek_str().as_deref() != Some("}") {
                            p.next();
                        }
                        p.next();
                        p.next();
                        break;
                    }
                } else {
                    p.pos = save;
                }
            }
            body_tokens.push(p.next().unwrap());
        }
        let body = parse_body_tokens(&body_tokens)?;
        return Ok(TemplateNode::IfCond { expr, body });
    }

    // 普通插值
    Ok(TemplateNode::Interpolation(inner))
}

fn parse_body_tokens(tokens: &[TokenTree]) -> Result<Vec<TemplateNode>, String> {
    let stream: TokenStream = tokens.iter().cloned().collect();
    let mut p = TokenStreamParser::new(stream);
    let mut nodes = Vec::new();
    while !p.is_empty() {
        nodes.push(parse_template_node(&mut p)?);
    }
    Ok(nodes)
}

// ─── 解析 style ────────────────────────────────────────────

fn parse_style_block(p: &mut TokenStreamParser) -> Result<StyleBlock, String> {
    let mut rules = Vec::new();
    while !p.is_empty() {
        p.expect(".")?;
        let selector_name = p.expect_ident()?;
        let mut sel_str = format!(".{}", selector_name);

        if p.peek_str().as_deref() == Some(":") {
            p.next();
            let pseudo = p.expect_ident()?;
            sel_str.push_str(&format!(":{}", pseudo));
        }

        // 读取属性块
        let block = p.expect_brace_group()?;
        let mut bp = TokenStreamParser::new(block);
        let mut properties = Vec::new();

        while !bp.is_empty() {
            let prop_name = bp.expect_ident()?;
            bp.expect(":")?;
            let mut val_tokens = Vec::new();
            while !bp.is_empty() && bp.peek_str().as_deref() != Some(",") {
                val_tokens.push(bp.next().unwrap());
            }
            let val: String = val_tokens.iter().map(|t| t.to_string()).collect();
            properties.push(StyleProp {
                name: prop_name,
                value: val.trim().to_string(),
            });
            if bp.peek_str().as_deref() == Some(",") {
                bp.next();
            }
        }

        rules.push(StyleRule { selector: sel_str, properties });
    }
    Ok(StyleBlock { rules })
}

// ─── html! 宏输入解析 ──────────────────────────────────────

pub fn parse_component_ref(input: TokenStream) -> Result<ComponentRef, String> {
    let mut p = TokenStreamParser::new(input);
    p.expect("<")?;
    let tag = p.expect_ident()?;
    let mut props = Vec::new();
    let mut events = Vec::new();

    loop {
        let next = p.peek_str().ok_or("Unexpected EOF")?;
        if next == ">" || next == "/" { break; }

        if next == "@" {
            p.next();
            let event_name = p.expect_ident()?;
            p.expect("=")?;
            let handler = p.expect_literal()?;
            events.push(EventBinding { name: event_name, handler });
        } else if next == ":" {
            p.next();
            let prop_name = p.expect_ident()?;
            p.expect("=")?;
            let value = p.expect_literal()?;
            props.push(Prop { name: prop_name, value });
        } else {
            break;
        }
    }

    if p.peek_str().as_deref() == Some("/") { p.next(); }
    p.expect(">")?;

    Ok(ComponentRef { tag, props, events })
}

pub fn parse_inline_template(input: TokenStream) -> Result<InlineTemplate, String> {
    let mut p = TokenStreamParser::new(input);
    let mut nodes = Vec::new();
    while !p.is_empty() {
        nodes.push(parse_template_node(&mut p)?);
    }
    Ok(InlineTemplate { nodes })
}

extern crate proc_macro;
use proc_macro::TokenStream;
use quote::quote;

mod parser;
mod codegen;

/// html!{ <Component : props /> } — 编译时展开为 ratatui 渲染代码
#[proc_macro]
pub fn html(input: TokenStream) -> TokenStream {
    let input_str = input.to_string().trim().to_string();

    // 尝试解析为组件引用 <Component :app />
    if input_str.starts_with('<') {
        let component = parser::parse_component_ref(input.into())
            .expect("Failed to parse component reference");
        let code = codegen::gen_component_call(&component);
        return code.into();
    }

    // 内联模板
    let template = parser::parse_inline_template(input.into())
        .expect("Failed to parse inline template");
    let code = codegen::gen_inline_template(&template);
    code.into()
}

/// include_tui!("ui/statusbar.tui") — 编译时读取 .tui 文件并生成代码
#[proc_macro]
pub fn include_tui(input: TokenStream) -> TokenStream {
    let lit: syn::LitStr = syn::parse(input).expect("Expected string literal");
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR")
        .expect("CARGO_MANIFEST_DIR not set");
    let full_path = std::path::Path::new(&manifest_dir).join(lit.value());

    let content = std::fs::read_to_string(&full_path)
        .unwrap_or_else(|e| panic!("Failed to read {}: {}", full_path.display(), e));

    let content_ts: proc_macro2::TokenStream = content.parse()
        .unwrap_or_else(|e| panic!("Failed to tokenize {}: {}", full_path.display(), e));

    let tui = parser::parse_tui_file(content_ts)
        .unwrap_or_else(|e| panic!("Failed to parse {}: {}", full_path.display(), e));

    let code = codegen::gen_tui_file(&tui);
    code.into()
}

use quote::quote;
use proc_macro2::TokenStream;
use crate::parser::*;

pub fn gen_tui_file(tui: &TuiFile) -> TokenStream {
    let mut tokens = TokenStream::new();

    if let Some(style) = &tui.style {
        tokens.extend(gen_style_block(style));
    }

    tokens.extend(gen_template_block(&tui.template));

    if let Some(script) = &tui.script {
        let block = &script.block;
        tokens.extend(quote! { #block });
    }

    tokens
}

fn gen_style_block(style: &StyleBlock) -> TokenStream {
    let mut match_arms = Vec::new();
    for rule in &style.rules {
        let selector = &rule.selector;
        let props = &rule.properties;
        let (class, pseudo) = if let Some(colon_pos) = selector.find(':') {
            (&selector[1..colon_pos], Some(&selector[colon_pos + 1..]))
        } else {
            (&selector[1..], None)
        };
        let style_expr = gen_style_expr(props);
        match pseudo {
            Some(p) => match_arms.push(quote! { (#class, Some(#p)) => #style_expr, }),
            None => match_arms.push(quote! { (#class, _) => #style_expr, }),
        }
    }
    quote! {
        fn style_resolve(class: &str, pseudo: Option<&str>) -> ratatui::style::Style {
            match (class, pseudo) {
                #(#match_arms)*
                _ => ratatui::style::Style::default(),
            }
        }
    }
}

fn gen_style_expr(props: &[StyleProp]) -> TokenStream {
    let mut fg = None;
    let mut bg = None;
    let mut bold = false;
    let mut dim = false;
    for prop in props {
        match prop.name.as_str() {
            "fg" => fg = Some(parse_color_value(&prop.value)),
            "bg" => bg = Some(parse_color_value(&prop.value)),
            "bold" => bold = prop.value == "true",
            "dim" => dim = prop.value == "true",
            _ => {}
        }
    }
    let mut s = quote! { ratatui::style::Style::default() };
    if let Some(fg_expr) = fg { s = quote! { #s.fg(#fg_expr) }; }
    if let Some(bg_expr) = bg { s = quote! { #s.bg(#bg_expr) }; }
    if bold { s = quote! { #s.add_modifier(ratatui::style::Modifier::BOLD) }; }
    if dim { s = quote! { #s.add_modifier(ratatui::style::Modifier::DIM) }; }
    s
}

fn parse_color_value(val: &str) -> TokenStream {
    match val {
        "auto" => quote! { crate::color_config::AUTO_FG_SENTINEL },
        "black" => quote! { ratatui::style::Color::Black },
        "red" => quote! { ratatui::style::Color::Red },
        "green" => quote! { ratatui::style::Color::Green },
        "yellow" => quote! { ratatui::style::Color::Yellow },
        "blue" => quote! { ratatui::style::Color::Blue },
        "magenta" => quote! { ratatui::style::Color::Magenta },
        "cyan" => quote! { ratatui::style::Color::Cyan },
        "white" => quote! { ratatui::style::Color::White },
        "darkgray" | "dark_gray" => quote! { ratatui::style::Color::DarkGray },
        _ => {
            if val.starts_with('[') && val.ends_with(']') {
                let inner = &val[1..val.len() - 1];
                let parts: Vec<u8> = inner.split(',').filter_map(|s| s.trim().parse().ok()).collect();
                if parts.len() == 3 {
                    let (r, g, b) = (parts[0], parts[1], parts[2]);
                    return quote! { ratatui::style::Color::Rgb(#r, #g, #b) };
                }
            }
            quote! { ratatui::style::Color::White }
        }
    }
}

fn gen_template_block(template: &TemplateBlock) -> TokenStream {
    let body = gen_nodes(&template.nodes);
    quote! {
        pub fn render(f: &mut ratatui::Frame, app: &crate::app::App, data: &[u8], area: ratatui::layout::Rect) {
            #body
        }
    }
}

fn gen_nodes(nodes: &[TemplateNode]) -> TokenStream {
    let stmts: Vec<_> = nodes.iter().map(gen_node).collect();
    quote! { #(#stmts)* }
}

fn gen_node(node: &TemplateNode) -> TokenStream {
    match node {
        TemplateNode::Element(elem) => gen_element(elem),
        TemplateNode::Text(text) => {
            let t = text.as_str();
            quote! { /* text: #t */ }
        }
        TemplateNode::Interpolation(expr) => {
            let e: proc_macro2::TokenStream = expr.parse().unwrap();
            quote! { /* interp: #e */ }
        }
        TemplateNode::ForLoop { var, iter, body } => {
            let v: proc_macro2::TokenStream = var.parse().unwrap();
            let it: proc_macro2::TokenStream = iter.parse().unwrap();
            let b = gen_nodes(body);
            quote! { for #v in #it { #b } }
        }
        TemplateNode::IfCond { expr, body } => {
            let e: proc_macro2::TokenStream = expr.parse().unwrap();
            let b = gen_nodes(body);
            quote! { if #e { #b } }
        }
    }
}

fn gen_element(elem: &Element) -> TokenStream {
    match elem.tag.as_str() {
        "Text" => gen_text_element(elem),
        "Statusbar" => gen_statusbar(elem),
        "Popup" => gen_popup(elem),
        "Row" => gen_row(elem),
        "Byte" => gen_byte(elem),
        "Scrollable" | "Scrollbar" => quote! {},
        _ => {
            let children = gen_nodes(&elem.children);
            quote! { #children }
        }
    }
}

fn gen_text_element(elem: &Element) -> TokenStream {
    let class = elem.classes.first().map(|c| c.as_str()).unwrap_or("");
    let content = gen_interpolation_content(&elem.children);
    quote! {
        {
            let sty = style_resolve(#class, None);
            let text = #content;
            spans.push(ratatui::text::Span::styled(text, sty));
        }
    }
}

fn gen_statusbar(elem: &Element) -> TokenStream {
    let children = gen_nodes(&elem.children);
    quote! {
        {
            f.render_widget(ratatui::widgets::Clear, ratatui::layout::Rect::new(0, area.height - 1, area.width, 1));
            let mut spans: Vec<ratatui::text::Span> = Vec::new();
            #children
            f.render_widget(
                ratatui::widgets::Paragraph::new(ratatui::text::Line::from(spans)),
                ratatui::layout::Rect::new(0, area.height - 1, area.width, 1),
            );
        }
    }
}

fn gen_popup(elem: &Element) -> TokenStream {
    let title = get_prop_value(elem, "title").unwrap_or_default();
    let title_tokens: proc_macro2::TokenStream = title.parse().unwrap_or_else(|_| quote! { "" });
    let children = gen_nodes(&elem.children);
    quote! {
        {
            let h = (area.height * 8 / 10).max(10).min(40);
            let w = (area.width * 9 / 10).max(30).min(80);
            let y = (area.height.saturating_sub(h)) / 2;
            let x = (area.width.saturating_sub(w)) / 2;
            let popup = ratatui::layout::Rect::new(x, y, w, h);
            f.render_widget(ratatui::widgets::Clear, popup);
            f.render_widget(
                ratatui::widgets::Block::default()
                    .borders(ratatui::widgets::Borders::ALL)
                    .border_style(ratatui::style::Style::default().fg(ratatui::style::Color::Gray).bg(ratatui::style::Color::Rgb(20, 20, 40)))
                    .title(#title_tokens)
                    .style(ratatui::style::Style::default().bg(ratatui::style::Color::Rgb(20, 20, 40))),
                popup,
            );
            #children
        }
    }
}

fn gen_row(elem: &Element) -> TokenStream {
    let children = gen_nodes(&elem.children);
    quote! {
        {
            #children
            lines.push(ratatui::text::Line::from(spans));
            spans = Vec::new();
        }
    }
}

fn gen_byte(elem: &Element) -> TokenStream {
    let offset = get_prop_value(elem, "offset")
        .map(|v| v.parse::<proc_macro2::TokenStream>().unwrap_or_else(|_| quote! { 0 }))
        .unwrap_or_else(|| quote! { 0 });
    quote! {
        {
            let byte_offset = #offset;
            if byte_offset < data.len() {
                let b = data[byte_offset];
                let sty = crate::byte_style(b, app.mode);
                let disp = crate::byte_disp(b, app.mode);
                spans.push(ratatui::text::Span::styled(disp, sty));
            }
        }
    }
}

fn gen_interpolation_content(nodes: &[TemplateNode]) -> TokenStream {
    let mut parts = Vec::new();
    for node in nodes {
        match node {
            TemplateNode::Text(t) => {
                let s = t.as_str();
                parts.push(quote! { #s });
            }
            TemplateNode::Interpolation(expr) => {
                let e: proc_macro2::TokenStream = expr.parse().unwrap();
                parts.push(quote! { &#e });
            }
            _ => {}
        }
    }
    if parts.is_empty() {
        quote! { String::new() }
    } else if parts.len() == 1 {
        parts[0].clone()
    } else {
        quote! { format!(#(#parts),*) }
    }
}

fn get_prop_value(elem: &Element, name: &str) -> Option<String> {
    elem.props.iter().find(|p| p.name == name).map(|p| p.value.clone())
}

pub fn gen_component_call(component: &ComponentRef) -> TokenStream {
    let tag = &component.tag;
    let tag_ident: proc_macro2::TokenStream = tag.parse().unwrap();
    quote! {
        {
            crate::components::#tag_ident::render(f, app, data, area);
        }
    }
}

pub fn gen_inline_template(template: &InlineTemplate) -> TokenStream {
    gen_nodes(&template.nodes)
}

