    let mut lx = Lexer::new(content);
    let mut template = None;
    let mut style = None;
    let mut script = None;

    while !lx.is_empty() {
        lx.skip_whitespace();
        if lx.is_empty() { break; }

        // 支持 <template> 和 template 两种语法
        let section = if lx.peek() == Some('<') && lx.peek2().map_or(false, |c| c.is_alphabetic()) {
            lx.advance(); // <
            let name = lx.read_ident();
            lx.skip_whitespace();
