/// read-bin-macros: 编译时 proc macro crate
///
/// 提供两个宏：
/// - `include_tui!("ui/xxx.tui")` — 读取 .tui 文件，解析 template/style/script，
///   生成 ratatui 渲染代码 + 样式查询函数 + 脚本函数
/// - `html!{ <Component /> }` — 展开为组件渲染调用
///
/// .tui 文件格式（类 Vue SFC）：
/// ```html
/// <template>
///   <Statusbar>
///     <Text class="mode">{{ app.mode.label() }}</Text>
///   </Statusbar>
/// </template>
/// <style>
///   .mode { fg: auto, bg: green }
/// </style>
/// <script lang="rust">
///   fn some_helper() -> String { ... }
/// </script>
/// ```
///
/// 依赖：proc-macro2, quote, syn（用于解析字符串字面量）
/// 不依赖重量级库，编译快速。

extern crate proc_macro;
use proc_macro::TokenStream;

mod parser;
mod codegen;

/// 编译时读取 .tui 文件并生成 Rust 代码
///
/// 用法：`read_bin_macros::include_tui!("ui/statusbar.tui");`
///
/// 生成的代码包含：
/// 1. `fn style_resolve(class, pseudo) -> Style` — 样式查询（从 <style> 块）
/// 2. `fn render(f, app, data, area)` — 渲染函数（从 <template> 块）
/// 3. <script lang="rust"> 中的函数直接透传
#[proc_macro]
pub fn include_tui(input: TokenStream) -> TokenStream {
    // 解析输入为字符串字面量（"ui/statusbar.tui"）
    let lit: syn::LitStr = syn::parse(input).expect("Expected string literal");

    // 拼接完整文件路径（相对于 Cargo.toml 所在目录）
    let manifest_dir = std::env::var("CARGO_MANIFEST_DIR")
        .expect("CARGO_MANIFEST_DIR not set");
    let full_path = std::path::Path::new(&manifest_dir).join(lit.value());

    // 读取 .tui 文件内容
    let content = std::fs::read_to_string(&full_path)
        .unwrap_or_else(|e| panic!("Failed to read {}: {}", full_path.display(), e));

    // 用自定义 lexer/parser 解析 .tui 文件（不依赖 syn 的 Parse trait）
    let tui = parser::parse_tui_str(&content)
        .unwrap_or_else(|e| panic!("Failed to parse {}: {}", full_path.display(), e));

    // 生成 Rust 代码（TokenStream）
    let code = codegen::gen_tui_file(&tui);
    code.into()
}

/// 编译时展开组件引用为渲染调用
///
/// 用法：`html!{ <Statusbar /> }`
/// 展开为：`crate::components::Statusbar::render(f, app, data, area);`
#[proc_macro]
pub fn html(input: TokenStream) -> TokenStream {
    let input_str = input.to_string();
    let component = parser::parse_component_ref_str(&input_str)
        .expect("Failed to parse component reference");
    let code = codegen::gen_component_call(&component);
    code.into()
}

