 fn gen_interpolation_content(nodes: &[TemplateNode]) -> TokenStream {
     let mut parts = Vec::new();
     for node in nodes {
         match node {
             TemplateNode::Text(t) => {
                 let s = t.as_str();
                 parts.push(quote! { #s });
             }
             TemplateNode::Interpolation(expr) => {
                 let e: proc_macro2::TokenStream = expr.parse().unwrap();
                 parts.push(quote! { &#e });
             }
             _ => {}
         }
